  "get_order_details": {
    "description": "Retrieves information for a specific order, including required items and destination.",
    "parameters": {
      "type": "object",
      "properties": {
        "order_id": {
          "type": "string",
          "description": "The order ID, e.g., 'ORD-990'."
        }
      },
      "required": [
        "order_id"
      ]
    },
    "example_output": {
      "order_id": "ORD-990",
      "sku": "SKU-BIO-007",
      "destination": "Phoenix, AZ"
    }
  },
  "get_sop_requirements": {
    "description": "Retrieves the protocol for a specific SOP code to identify temperature constraints and required materials.",
    "parameters": {
      "type": "object",
      "properties": {
        "sop_id": {
          "type": "string",
          "description": "The SOP code, e.g., 'TCF-04'."
        }
      },
      "required": [
        "sop_id"
      ]
    },
    "example_output": {
      "sop_id": "TCF-04",
      "threshold_temp_c": 35,
      "max_exposure_minutes": 30,
      "packaging_types": [
        "insulated_cooler",
        "phase_change_material",
        "data_logger"
      ]
    }
  },
  "get_inventory_by_zone": {
    "description": "Searches for specific SKUs within a designated warehouse zone to retrieve their Bin IDs and stock levels.",
    "parameters": {
      "type": "object",
      "properties": {
        "zone_id": {
          "type": "string",
          "description": "The warehouse zone, e.g., 'ZONE-SUPPLY-SHELF'."
        },
        "sku_list": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of target SKUs to find (e.g., ['VIP-COOLER-MD', 'DATA-LOGGER-DIGITAL'])."
        }
      },
      "required": [
        "zone_id",
        "sku_list"
      ]
    },
    "example_output": {
      "results": [
        {
          "sku": "VIP-COOLER-MD",
          "bin_id": "BIN-S-101",
          "quantity": 15
        },
        {
          "sku": "DATA-LOGGER-DIGITAL",
          "bin_id": "BIN-S-202",
          "quantity": 50
        }
      ]
    }
  },
  "locate_sku_storage": {
    "description": "Returns the specific storage location (Bin ID) and environment type for a particular SKU.",
    "parameters": {
      "type": "object",
      "properties": {
        "sku_id": {
          "type": "string",
          "description": "The SKU to locate."
        }
      },
      "required": [
        "sku_id"
      ]
    },
    "example_output": {
      "bin_id": "COLD-STORAGE-07",
      "environment": "Chilled"
    }
  },
  "get_facility_node": {
    "description": "Retrieves the Node ID for specific warehouse functional locations such as docks.",
    "parameters": {
      "type": "object",
      "properties": {
        "location_type": {
          "type": "string",
          "description": "Type of location, e.g., 'Chilled-Dock'."
        }
      },
      "required": [
        "location_type"
      ]
    },
    "example_output": {
      "node_id": "DOCK-NODE-CHILL-A"
    }
  },
  "find_available_robot": {
    "description": "Identifies an idle AMR (Autonomous Mobile Robot) suitable for handling the task.",
    "parameters": {
      "type": "object",
      "properties": {
        "status": {
          "type": "string",
          "enum": [
            "idle"
          ]
        }
      },
      "required": [
        "status"
      ]
    },
    "example_output": {
      "robot_id": "AMR-94"
    }
  },
  "execute_robot_move": {
    "description": "Dispatches a robot to a specific Bin ID or Node ID.",
    "parameters": {
      "type": "object",
      "properties": {
        "robot_id": {
          "type": "string"
        },
        "target_id": {
          "type": "string"
        }
      },
      "required": [
        "robot_id",
        "target_id"
      ]
    }
  },
  "execute_robot_pick": {
    "description": "Commands a robot to pick an item from a bin. Picking temperature-controlled items triggers the custody clock.",
    "parameters": {
      "type": "object",
      "properties": {
        "robot_id": {
          "type": "string"
        },
        "sku_id": {
          "type": "string"
        },
        "bin_id": {
          "type": "string"
        }
      },
      "required": [
        "robot_id",
        "sku_id",
        "bin_id"
      ]
    }
  },
