    "description": "Finalizes the order by applying specified packaging materials and staging the payload at the designated dock. This action stops the Cold Chain clock.",
    "parameters": {
      "type": "object",
      "properties": {
        "robot_id": {
          "type": "string"
        },
        "order_id": {
          "type": "string"
        },
